class Solution:
    def maxHats(self, hats, n):
        hats.sort(reverse=True);
        people = [i for i in range(1, n+1)];
        hats.sort();
        for i in range(len(hats)):
            for j in range(len(people)):
                if hats[i] >= people[j]:
                    people[j] = 0;
                    break;
        return len([i for i in people if i != 0]);

def main():
    n = int(input());
    hats = list(map(int, input().split()))
    hats.sort();
    n = int(input());
    solution = Solution();
    print(solution.maxHats(hats, n));

