class Solution {
public:
    int maxHats(vector<int>& hats, int n) {
        sort(hats.begin(), hats.end());
        sort(hats.rbegin(), hats.rend());
        int result = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < hats.size(); j++) {
                if (hats[j] >= i + 1) {
                    result++;
                    hats[j] = 0;
                    j = hats.size();
                }
            }
        }
        return result;
    }
};

int main() {
    int n;
    cin >> n;
    vector<int> hats(n);
    for (int i = 0; i < n; i++) {
        cin >> hats[i];
    }
    sort(hats.begin(), hats.end());
    sort(hats.rbegin(), hats.rend());

    int n;
    cin >> n;

    Solution solution;
    cout << solution.maxHats(hats, n) << endl;

    return 0;
}
